import { useParams } from "react-router-dom";
import { useState, useEffect } from "react";

/* Severity mapping */
const severityMap = { P0: 4, P1: 3, P2: 2, P3: 1 };

export default function IncidentDetail() {
  const { id } = useParams();

  const [trend, setTrend] = useState([]);
  const [loading, setLoading] = useState(true);
  const [closing, setClosing] = useState(false);

  const [form, setForm] = useState({
    start: "",
    end: "",
    rootCause: "",
    fix: "",
    prevention: ""
  });

  /* FETCH TREND */
  useEffect(() => {
    fetch(`http://localhost:8000/incident/${id}/trend`)
      .then(res => res.json())
      .then(data => {
        setTrend(Array.isArray(data) ? data : []);
        setLoading(false);
      })
      .catch(() => {
        setLoading(false);
      });
  }, [id]);

  /* FORM CHANGE */
  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  /* CLOSE INCIDENT */
  const handleSubmit = async (e) => {
    e.preventDefault();
    setClosing(true);

    try {
      const res = await fetch(`http://localhost:8000/close/${id}`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(form)
      });

      const data = await res.json();

      if (data.error) {
        alert(data.error);
      } else {
        alert("Incident Closed ✅");
      }
    } catch {
      alert("Error closing incident");
    }

    setClosing(false);
  };

  /* SIMPLE GRAPH CALCULATION */
  const max = 4;

  return (
    <div style={page}>
      <h2>Incident #{id}</h2>

      {/* GRAPH */}
      <div style={card}>
        <h3>📊 Severity Trend</h3>

        {loading ? (
          <p>Loading...</p>
        ) : trend.length === 0 ? (
          <p>No data</p>
        ) : (
          <div style={graph}>
            {trend.map((t, i) => {
              const value = severityMap[t.severity] || 1;
              const height = (value / max) * 100;

              return (
                <div key={i} style={barContainer}>
                  <div
                    style={{
                      ...bar,
                      height: `${height}%`,
                      background: getColor(t.severity)
                    }}
                  />
                  <span style={label}>{t.severity}</span>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* RCA FORM */}
      <div style={card}>
        <h3>🛠 Close Incident</h3>

        <form onSubmit={handleSubmit} style={formStyle}>
          <input type="datetime-local" name="start" onChange={handleChange} required />
          <input type="datetime-local" name="end" onChange={handleChange} required />
          <input name="rootCause" placeholder="Root Cause" onChange={handleChange} required />
          <input name="fix" placeholder="Fix" onChange={handleChange} />
          <input name="prevention" placeholder="Prevention" onChange={handleChange} />

          <button type="submit" disabled={closing}>
            {closing ? "Closing..." : "Close Incident"}
          </button>
        </form>
      </div>
    </div>
  );
}

/* COLORS */
function getColor(sev) {
  if (sev === "P0") return "#ff4d4f"; // red
  if (sev === "P1") return "#ff9800"; // orange
  if (sev === "P2") return "#fbc02d"; // yellow
  if (sev === "P3") return "#4caf50"; // green
  return "#999";
}

/* STYLES */
const page = {
  padding: "20px",
  background: "#f4f6f8",
  minHeight: "100vh"
};

const card = {
  background: "#fff",
  padding: "20px",
  borderRadius: "12px",
  marginTop: "20px"
};

const graph = {
  display: "flex",
  alignItems: "flex-end",
  height: "200px",
  gap: "10px"
};

const barContainer = {
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
  width: "40px"
};

const bar = {
  width: "100%",
  borderRadius: "6px"
};

const label = {
  marginTop: "5px",
  fontSize: "12px"
};

const formStyle = {
  display: "flex",
  flexDirection: "column",
  gap: "10px"
};
